const seed = async () => {
  try {
    await mongoose.connect(process.env.MONGO_URI);
    console.log('MongoDB connected');

    await Course.deleteMany({});
    console.log('Old courses cleared');

    const inserted = await Course.insertMany(courses);
    console.log(`\n${inserted.length} courses inserted successfully:\n`);
    inserted.forEach((c) => console.log(` ✓ ${c.title} — ${c.resources.length} resources`));

    await mongoose.disconnect();
    console.log('\nDone. MongoDB disconnected.');
    process.exit(0);
  } catch (err) {
    console.error('Seed error:', err.message);
    process.exit(1);
  }
};

seed();